šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¦ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬
    var displayClassName by remember { mutableStateOf("") }
    var rollPrefix  by remember { mutableStateOf("") }
    var students    by remember { mutableStateOf<List<Student>>(emptyList()) }
    var dataReady   by remember(className) { mutableStateOf(false) }
    val sortedRolls by remember(students) {
        mutableStateOf(
            students.mapNotNull {
                it.studentId.reversed().takeWhile(Char::isDigit).reversed().toIntOrNull()
            }.sorted()
        )
    }

    // TTS
    val tts = remember { TtsManager.getRollCallEngine(context) }
    DisposableEffect(Unit) { onDispose { tts.stop() } }

    LaunchedEffect(className) {
        dataReady = false
        tts.configure(prefs.ttsSpeed, voiceModelState, ttsEnabled)
        kotlinx.coroutines.coroutineScope {
            val classInfoDeferred = async { classManager.getClassById(className) }
            val studentsDeferred = async { sessionManager.getCachedStudents(className) }
            val classInfo = classInfoDeferred.await()
            displayClassName = classInfo?.className ?: "Class"
            rollPrefix = classInfo?.rollPrefix ?: ""
            students = studentsDeferred.await()
        }
        dataReady = true
    }

    var rollNumber         by remember { mutableIntStateOf(startRoll) }
    var latestRoll         by remember { mutableIntStateOf(startRoll) }
    var markedStudent      by remember { mutableStateOf<MarkedStudent?>(null) }
    var showSpeedDropdown  by remember { mutableStateOf(false) }
    var showMultiTapDialog by remember { mutableStateOf(false) }
    var showBackDialog by remember { mutableStateOf(false) }
    var hasRollCallChanges by remember { mutableStateOf(false) }
    var lastHandledTime    by remember { mutableLongStateOf(0L) }
    var ttsReady by remember { mutableStateOf(tts.isReady()) }
    var firstRollUnlocked by remember(className) { mutableStateOf(!ttsEnabled) }
    var previousTtsEnabled by remember { mutableStateOf(ttsEnabled) }

    LaunchedEffect(className) {
        firstRollUnlocked = !ttsEnabled
    }

    LaunchedEffect(speedIndexState, voiceModelState) {
        tts.configure(prefs.ttsSpeed, voiceModelState, ttsEnabled)
        if (!ttsEnabled) {
            tts.stop()
            firstRollUnlocked = true
            ttsReady = true
        }
    }

    LaunchedEffect(ttsEnabled, voiceModelState, dataReady, rollNumber) {
        if (!dataReady) return@LaunchedEffect

        if (!ttsEnabled) {
            previousTtsEnabled = false
            tts.stop()
            firstRollUnlocked = true
            ttsReady = true
            return@LaunchedEffect
        }

        val wasEnabled = previousTtsEnabled
        previousTtsEnabled = true
        if (!wasEnabled) {
            tts.configure(prefs.ttsSpeed, voiceModelState, enabled = true)
            ttsReady = tts.isReady()
            firstRollUnlocked = false
            val currentStudent = students.firstOrNull {
                it.studentId.reversed().takeWhile(Char::isDigit).reversed().toIntOrNull() == rollNumber
            }
            val rollId = currentStudent?.studentId ?: rollNumber.toString()
            tts.speakRoll(
                rollId = rollId,
                utteranceId = "qm_reenable_${className}_${rollNumber}",
                onStart = {
                    ttsReady = true
                    firstRollUnlocked = true
                }
            )
        }
    }

    BackHandler { showBackDialog = true }

    fun studentForRoll(roll: Int): Student? =
        students.firstOrNull {
            it.studentId.reversed().takeWhile(Char::isDigit).reversed().toIntOrNull() == roll
        }

    fun extractRollInt(studentId: String): Int =
        studentId.reversed().takeWhile(Char::isDigit).reversed().toIntOrNull() ?: 0

    fun handleExit(action: String) {
        showBackDialog = false
        when (action) {
            "SAVE" -> onExit() // Just exit, repository keeps active session
            "DISCARD" -> {
                scope.launch {
                    // Need to add discardSession to SessionManager if it's not there
                    // Looking at SessionManager.kt, it's missing. I'll use repo for now or add it.
                    // Actually, I should add it to SessionManager.
                    // For now, I'll keep it as it is if I'm only refactoring, but I should probably add it.
                    // Let's assume I'll add it.
                    sessionManager.discardSession(className)
                    onExit()
                }
            }
        }
    }

    if (showMultiTapDialog) MultiTapDialog(onDismiss = { showMultiTapDialog = false })
    if (showBackDialog) {
        ExitSessionDialog(
            onDismiss = { showBackDialog = false },
            onSave = { handleExit("SAVE") },
            onDiscard = { handleExit("DISCARD") },
            showDiscard = showDiscardOnBack,
            requireDiscardConfirmation = hasRollCallChanges
        )
    }

    // Sync initial wheel position to first valid active roll in range and queue first speech immediately.
    LaunchedEffect(sortedRolls, startRoll) {
        if (sortedRolls.isNotEmpty()) {
            val firstValid = sortedRolls.firstOrNull { it >= startRoll } ?: sortedRolls.first()
            rollNumber = firstValid
            latestRoll = firstValid
            if (!ttsEnabled) {
                firstRollUnlocked = true
                return@LaunchedEffect
            }
            firstRollUnlocked = false
            val firstStudent = studentForRoll(firstValid)
            val rollId = firstStudent?.studentId ?: firstValid.toString()
            tts.speakRoll(
                rollId = rollId,
                utteranceId = "qm_first_roll",
                speechRateOverride = maxOf(prefs.ttsSpeed, 2.0f)
            ) {
                firstRollUnlocked = true
            }
        }
    }

    LaunchedEffect(className, voiceModelState, speedIndexState) {
        if (!ttsEnabled) {
            ttsReady = true
            return@LaunchedEffect
        }
        ttsReady = tts.isReady()
        repeat(120) {
            if (tts.isReady()) {
                ttsReady = true
                return@LaunchedEffect
            }
            kotlinx.coroutines.delay(50)
        }
        ttsReady = tts.isReady()
    }

    val hPad = responsiveHPad()
    val interactionEnabled = dataReady && firstRollUnlocked

    Scaffold(
        containerColor = AppBackground,
        topBar = {
            TopAppBar(
                title = {
                    Box(
                        modifier = Modifier
                            .clip(RoundedCornerShape(14.dp))
                            .background(CardBackground)
                            .border(1.dp, BorderColor, RoundedCornerShape(14.dp))
                            .height(40.dp)
                            .padding(horizontal = 14.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            "Roll Call Screen",
                            fontWeight = FontWeight.Bold,
                            fontSize = 18.sp,
                            color = TextPrimary
                        )
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = AppBackground),
                actions = {
                    // TTS Speed Control moved to right
                    Box(modifier = Modifier.padding(end = 12.dp)) {
                        Row(
                            modifier = Modifier
                                .height(40.dp)
                                .clip(RoundedCornerShape(14.dp))
                                .background(CardBackground)
                                .border(1.dp, BorderColor, RoundedCornerShape(14.dp))
                                .clickable { showSpeedDropdown = !showSpeedDropdown }
                                .padding(horizontal = 12.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(if (ttsEnabled) Icons.Default.VolumeUp else Icons.Default.VolumeOff, "Speaker", tint = TextSecondary, modifier = Modifier.size(16.dp))
                            Spacer(Modifier.width(8.dp))
                            Text(
                                prefs.ttsSpeedLabel,
                                color = AccentBlue,
                                fontWeight = FontWeight.Bold,
                                fontSize = 13.sp
                            )
                            Spacer(Modifier.width(4.dp))
                            Icon(Icons.Default.KeyboardArrowDown, "Expand", tint = TextSecondary, modifier = Modifier.size(14.dp))
                        }
                        if (showSpeedDropdown) {
                            SpeedDropdown(
                                selectedIndex = speedIndexState,
                                onSpeedChange = { selectedIndex ->
                                    prefs.ttsSpeedIndex = selectedIndex
                                    tts.configure(prefs.ttsSpeed, voiceModelState, prefs.isTtsEnabled)
                                    if (!prefs.isTtsEnabled) {
                                        tts.stop()
                                        firstRollUnlocked = true
                                    }
                                },
                                onDismiss = { showSpeedDropdown = false }
                            )
                        }
                    }
                }
            )
        }
    ) { paddingValues ->
        if (!interactionEnabled) {
            Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    CircularProgressIndicator(color = AccentBlue)
                    Text(
                        if (dataReady) "Loading TTS" else "Loading session",
                        color = TextSecondary,
                        fontSize = 14.sp,
                        fontWeight = FontWeight.Medium
                    )
                }
            }
            return@Scaffold
        }

                // Logic block moved down from above for consistency
                val totalStudents   = sortedRolls.size.coerceAtLeast(1)
                val lastRollValue   = sortedRolls.lastOrNull() ?: rollNumber
                val sessionFinished = latestRoll > lastRollValue
                val currentStudent  = studentForRoll(rollNumber)?.name ?: "Roll $rollNumber"

                val hundreds = (rollNumber / 100) % 10
                val tens     = (rollNumber / 10)  % 10
                val ones     =  rollNumber        % 10

                val screenH   = LocalConfiguration.current.screenHeightDp.dp
                val isCompact = screenH < 700.dp
                val sp2: androidx.compose.ui.unit.TextUnit  = if (isCompact) 12.sp else 14.sp
                val sp3: androidx.compose.ui.unit.TextUnit  = if (isCompact) 14.sp else 16.sp
                val sp4: androidx.compose.ui.unit.TextUnit  = if (isCompact) 16.sp else 18.sp
                val gap1: Dp = if (isCompact) 6.dp  else 10.dp
                val gap2: Dp = if (isCompact) 8.dp  else 12.dp

                fun updateRoll(h: Int, t: Int, o: Int) {
                    val requested = ((h * 100) + (t * 10) + o).coerceIn(1, 999)
                    if (sortedRolls.isEmpty()) {
                        rollNumber = requested
                        return
                    }
                    rollNumber = sortedRolls.firstOrNull { it >= requested } ?: sortedRolls.last()
                }

                fun handleAttendance(status: Int) {
                    if (!interactionEnabled) return
                    val now = System.currentTimeMillis()
                    if (now - lastHandledTime < 50L) { showMultiTapDialog = true; return }
                    lastHandledTime = now
                    val student = studentForRoll(rollNumber)
                    if (student == null) return
                    val respondedRoll = rollNumber
                    val respondedStudentId = student.studentId
                    val respondedStudentName = currentStudent
                    hasRollCallChanges = true
                    markedStudent = MarkedStudent(
                        roll = respondedRoll,
                        studentId = respondedStudentId,
                        name = respondedStudentName,
                        status = status
                    )
                    scope.launch {
                        sessionManager.markStudent(className, respondedStudentId, status)
                        val sessionRecords = sessionManager.getSessionAttendance(className)
                        val markedRecords = sessionRecords.filter { it.status != -1 }
                        val highestMarkedRoll = markedRecords
                            .map { extractRollInt(it.studentId) }
                            .filter { it > 0 }
                            .maxOrNull()
                            ?: respondedRoll
                        sessionManager.updateProgress(
                            className,
                            highestMarkedRoll,
                            markedRecords.size
                        )
                    }
                    if (respondedRoll >= latestRoll) {
                        val nextRoll = sortedRolls.firstOrNull { it > respondedRoll }
                        if (nextRoll != null) {
                            rollNumber = nextRoll
                            latestRoll = nextRoll
                            val nextStudent = studentForRoll(rollNumber)
                            val rollId = nextStudent?.studentId ?: rollNumber.toString()
                            if (ttsEnabled) tts.speakRoll(rollId)
                        } else {
                            latestRoll = lastRollValue + 1
                        }
                    }
                }

                val progress = if (latestRoll > lastRollValue) 1f else sortedRolls.indexOf(latestRoll).coerceAtLeast(0).toFloat() / totalStudents.toFloat()

                Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.TopCenter) {
            Column(
                modifier = modifier.fillMaxHeight().widthIn(max = 520.dp)
                    .padding(paddingValues).padding(horizontal = hPad),
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Spacer(Modifier.height(gap1))

                // Progress pill
                Column(modifier = Modifier.fillMaxWidth()
                    .clip(RoundedCornerShape(16.dp)).background(CardBackground)
                    .border(1.dp, BorderColor, RoundedCornerShape(16.dp))
                    .padding(horizontal = 16.dp, vertical = 12.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                        Icon(Icons.Default.Book, null, tint = AccentBlue, modifier = Modifier.size(14.dp))
                        Spacer(Modifier.width(6.dp))
                        Text(displayClassName, fontSize = sp2, fontWeight = FontWeight.Bold, color = TextPrimary,
                            fontFamily = FontFamily.Monospace, maxLines = 1, overflow = TextOverflow.Ellipsis, modifier = Modifier.weight(1f))
                        val currentIdx = if (latestRoll > lastRollValue) totalStudents else sortedRolls.indexOf(latestRoll).coerceAtLeast(0)
                        Text("$currentIdx/$totalStudents", fontSize = sp2, fontWeight = FontWeight.Bold,
                            color = AccentBlue, fontFamily = FontFamily.Monospace)
                    }
                    LinearProgressIndicator(
                        progress          = { progress.coerceIn(0f, 1f) },
                        modifier          = Modifier.fillMaxWidth().height(6.dp).clip(RoundedCornerShape(3.dp)),
                        color             = AccentBlue, trackColor = BorderColor,
                        strokeCap         = androidx.compose.ui.graphics.StrokeCap.Round,
                        gapSize           = 0.dp, drawStopIndicator = {}
                    )
                }

                Spacer(Modifier.height(gap1))

                // Student name
                val nameScrollState: ScrollState = rememberScrollState()
                Row(modifier = Modifier.fillMaxWidth()
                    .clip(RoundedCornerShape(14.dp)).background(CardBackground)
                    .border(1.dp, BorderColor, RoundedCornerShape(14.dp))
                    .padding(horizontal = 16.dp, vertical = 12.dp),
                    verticalAlignment = Alignment.CenterVertically) {
                    Row(modifier = Modifier.weight(1f).horizontalScroll(nameScrollState)) {
                        Text(currentStudent, fontSize = sp4, fontWeight = FontWeight.Bold, color = TextPrimary, softWrap = false)
                    }
                }

                Spacer(Modifier.height(gap2))

                // Issue #18: digit wheel shows rollPrefix from DB instead of hardcoded "BT24CSE"
                Column(modifier = Modifier.wrapContentWidth()
                    .clip(RoundedCornerShape(20.dp)).background(CardBackground)
                    .border(1.dp, BorderColor, RoundedCornerShape(20.dp))
                    .padding(horizontal = 16.dp, vertical = 14.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    if (rollPrefix.isNotEmpty()) {
                        Text(rollPrefix, fontSize = sp3, fontWeight = FontWeight.Bold,
                            color = AccentBlue, letterSpacing = 2.sp, fontFamily = FontFamily.Monospace)
                    }
                    Box(modifier = Modifier.width(52.dp * 3 + 8.dp * 2).height(2.dp)
                        .clip(RoundedCornerShape(1.dp)).background(BorderColor.copy(alpha = 0.6f)))
                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        DigitWheel(hundreds, { updateRoll(it, tens, ones)      }, Modifier.width(52.dp))
                        DigitWheel(tens,     { updateRoll(hundreds, it, ones)  }, Modifier.width(52.dp))
                        DigitWheel(ones,     { updateRoll(hundreds, tens, it)  }, Modifier.width(52.dp))
                    }
                }

                Spacer(Modifier.height(gap2))

                // Navigation
                Row(modifier = Modifier.clip(RoundedCornerShape(12.dp)).background(CardBackground)
                    .border(1.dp, BorderColor, RoundedCornerShape(12.dp))
                    .padding(horizontal = 6.dp, vertical = 4.dp),
                    horizontalArrangement = Arrangement.spacedBy(2.dp), verticalAlignment = Alignment.CenterVertically) {
                    NavBtn({
                        val prev = sortedRolls.lastOrNull { it < rollNumber }
                        if (prev != null) rollNumber = prev
                    }) { Icon(Icons.AutoMirrored.Filled.ArrowBack, "Prev", Modifier.size(15.dp)) }
                    Box(Modifier.width(1.dp).height(18.dp).background(BorderColor))
                    Button(onClick = { 
                        // Jump to the furthest student reached or the last student if finished
                        rollNumber = if (latestRoll > lastRollValue) lastRollValue else latestRoll
                    },
                        colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent, contentColor = AccentBlue),
                        shape = RoundedCornerShape(8.dp), modifier = Modifier.height(36.dp),
                        elevation = null, contentPadding = PaddingValues(horizontal = 12.dp)) {
                        Icon(Icons.Default.SkipNext, "Latest", Modifier.size(15.dp))
                        Spacer(Modifier.width(4.dp))
                        Text("Latest", fontSize = sp2, fontWeight = FontWeight.SemiBold)
                    }
                    Box(Modifier.width(1.dp).height(18.dp).background(BorderColor))
                    NavBtn({
                        val next = sortedRolls.firstOrNull { it > rollNumber && it <= latestRoll }
                        if (next != null) rollNumber = next
                    }) { Icon(Icons.AutoMirrored.Filled.ArrowForward, "Next", Modifier.size(15.dp)) }
                }

                Spacer(Modifier.height(gap2))

                // Absent / Present buttons
                Row(modifier = Modifier.fillMaxWidth().multiTouchGuard { showMultiTapDialog = true },
                    horizontalArrangement = Arrangement.spacedBy(14.dp)) {
                    Button(onClick = { handleAttendance(0) }, modifier = Modifier.weight(1f).height(64.dp),
                        colors = ButtonDefaults.buttonColors(containerColor = AbsentRed.copy(alpha = 0.15f), contentColor = AbsentRed),
                        border = BorderStroke(1.dp, AbsentRed.copy(alpha = 0.5f)), shape = RoundedCornerShape(16.dp), elevation = null,
                        enabled = interactionEnabled && studentForRoll(rollNumber) != null) {
                        Text("Absent", fontSize = 20.sp, fontWeight = FontWeight.Bold)
                    }
                    Button(onClick = { handleAttendance(1) }, modifier = Modifier.weight(1f).height(64.dp),
                        colors = ButtonDefaults.buttonColors(containerColor = PresentGreen.copy(alpha = 0.15f), contentColor = PresentGreen),
                        border = BorderStroke(1.dp, PresentGreen.copy(alpha = 0.5f)), shape = RoundedCornerShape(16.dp), elevation = null,
                        enabled = interactionEnabled && studentForRoll(rollNumber) != null) {
                        Text("Present", fontSize = 20.sp, fontWeight = FontWeight.Bold)
                    }
                }

                Spacer(Modifier.height(gap1))

                // Previously marked card
                Box(modifier = Modifier.fillMaxWidth().height(70.dp), contentAlignment = Alignment.Center) {
                    val currentMarked = markedStudent
                    if (currentMarked != null) {
                        androidx.compose.animation.AnimatedVisibility(visible = true,
                            enter = fadeIn(tween(160)) + slideInVertically(tween(160)) { 16 },
                            exit  = fadeOut(tween(120)) + scaleOut(tween(120), targetScale = 0.97f)) {
                            PreviouslyMarkedCard(currentMarked, sp3 * 0.85f, sp2)
                        }
                    }
                }

                Spacer(Modifier.weight(1f))

                // Finish
                Button(
                    onClick  = { if (sessionFinished) onFinish(className) },
                    modifier = Modifier.fillMaxWidth().padding(bottom = 16.dp).height(56.dp),
                    colors   = ButtonDefaults.buttonColors(
                        containerColor = if (sessionFinished) AccentBlue else BorderColor,
                        contentColor   = if (sessionFinished) Color.White else TextSecondary
                    ),
                    shape    = RoundedCornerShape(16.dp),
                    enabled  = sessionFinished
                ) {
                    Icon(Icons.Default.CheckCircle, null, modifier = Modifier.size(20.dp))
                    Spacer(Modifier.width(8.dp))
                    Text("Summarize & Save", fontSize = sp3, fontWeight = FontWeight.Bold)
                }
            }
        }
    }
}

@Composable
private fun NavBtn(onClick: () -> Unit, content: @Composable () -> Unit) {
    Button(onClick = onClick,
        colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent, contentColor = TextSecondary),
        shape = RoundedCornerShape(8.dp), modifier = Modifier.height(36.dp),
        elevation = null, contentPadding = PaddingValues(horizontal = 12.dp)) { content() }
}

@Composable
fun PreviouslyMarkedCard(marked: MarkedStudent, sp1: androidx.compose.ui.unit.TextUnit, sp2: androidx.compose.ui.unit.TextUnit) {
    val statusColor = if (marked.status == 1) PresentGreen else AbsentRed
    Row(modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(14.dp)).background(CardBackground)
        .border(1.dp, BorderColor, RoundedCornerShape(14.dp))
        .padding(horizontal = 14.dp, vertical = 10.dp),
        horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
        Column(modifier = Modifier.weight(1f)) {
            Text("PREVIOUSLY MARKED", color = TextSecondary, fontSize = sp1, fontWeight = FontWeight.Bold, letterSpacing = 1.sp)
            Spacer(Modifier.height(3.dp))
            Row(verticalAlignment = Alignment.CenterVertically) {
                Text(String.format("%03d", marked.roll), color = TextSecondary, fontSize = sp2,
                    fontFamily = FontFamily.Monospace, fontWeight = FontWeight.Medium, modifier = Modifier.width(36.dp))
                Row(modifier = Modifier.weight(1f).horizontalScroll(rememberScrollState())) {
                    Text(
                        marked.name,
                        color = TextPrimary,
                        fontSize = sp2,
                        fontWeight = FontWeight.SemiBold,
                        softWrap = false
                    )
                }
            }
        }
        Spacer(Modifier.width(10.dp))
        Box(modifier = Modifier.size(32.dp).clip(RoundedCornerShape(9.dp))
            .background(statusColor.copy(alpha = 0.15f)).border(1.dp, statusColor.copy(alpha = 0.4f), RoundedCornerShape(9.dp)),
            contentAlignment = Alignment.Center) {
            Text(if (marked.status == 1) "P" else "A", color = statusColor, fontWeight = FontWeight.Bold, fontSize = sp2)
        }
    }
}

@Composable
fun SpeedDropdown(selectedIndex: Int, onSpeedChange: (Int) -> Unit, onDismiss: () -> Unit) {
    DropdownMenu(expanded = true, onDismissRequest = onDismiss, shape = RoundedCornerShape(14.dp), containerColor = CardBackground) {
        PreferencesManager.TTS_SPEED_LABELS.forEachIndexed { index, label ->
            DropdownMenuItem(
                modifier = Modifier.width(104.dp),
                text = {
                    Text(
                        label,
                        color = if (selectedIndex == index) AccentBlue else TextPrimary,
                        fontWeight = FontWeight.SemiBold,
                        fontSize = 13.sp
                    )
                },
                onClick = { onSpeedChange(index); onDismiss() }
            )
        }
    }
}

@Composable
fun DigitWheel(value: Int, onValueChanged: (Int) -> Unit, modifier: Modifier = Modifier) {
    val screenH    = LocalConfiguration.current.screenHeightDp.dp
    val itemHeight = (screenH * 0.07f).coerceIn(44.dp, 64.dp)
    var previousRoll by remember { mutableIntStateOf(value) }
    val isForward    = value > previousRoll
    previousRoll     = value
    val transitionSpec = {
        if (isForward)
            (slideInVertically(tween(120)) { h -> h } + fadeIn(tween(100)))
                .togetherWith(slideOutVertically(tween(120)) { h -> -h } + fadeOut(tween(100)))
        else
            (slideInVertically(tween(120)) { h -> -h } + fadeIn(tween(100)))
                .togetherWith(slideOutVertically(tween(120)) { h -> h } + fadeOut(tween(100)))
    }
    Box(modifier = modifier.height(itemHeight * 3).clip(RoundedCornerShape(14.dp))
        .background(Color(0xFF1E293B)).border(1.dp, Color(0xFF334155), RoundedCornerShape(14.dp))) {
        Box(modifier = Modifier.align(Alignment.Center).fillMaxWidth().height(itemHeight)
            .background(AccentBlue.copy(alpha = 0.15f)).border(1.dp, AccentBlue.copy(alpha = 0.3f)))
        Column(modifier = Modifier.fillMaxSize(), horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center) {
            val previous = ((value - 1) % 10 + 10) % 10
            val next     = ((value + 1) % 10 + 10) % 10
            AnimatedContent(previous, transitionSpec = { transitionSpec() }, label = "prev") { v ->
                Text(v.toString(), fontSize = 22.sp, fontWeight = FontWeight.Bold,
                    color = TextSecondary.copy(alpha = 0.5f),
                    modifier = Modifier.height(itemHeight).fillMaxWidth().wrapContentHeight(Alignment.CenterVertically)
                        .graphicsLayer { rotationX = 24f; scaleX = 0.85f; scaleY = 0.85f; cameraDistance = 8 * density },
                    textAlign = TextAlign.Center)
            }
            AnimatedContent(value, transitionSpec = { transitionSpec() }, label = "curr") { v ->
                Text(v.toString(), fontSize = 28.sp, fontWeight = FontWeight.Bold, color = AccentBlue,
                    modifier = Modifier.height(itemHeight).fillMaxWidth().wrapContentHeight(Alignment.CenterVertically),
                    textAlign = TextAlign.Center)
            }
            AnimatedContent(next, transitionSpec = { transitionSpec() }, label = "next") { v ->
                Text(v.toString(), fontSize = 22.sp, fontWeight = FontWeight.Bold,
                    color = TextSecondary.copy(alpha = 0.5f),
                    modifier = Modifier.height(itemHeight).fillMaxWidth().wrapContentHeight(Alignment.CenterVertically)
                        .graphicsLayer { rotationX = -24f; scaleX = 0.85f; scaleY = 0.85f; cameraDistance = 8 * density },
                    textAlign = TextAlign.Center)
            }
        }
    }
}








